import React, { useState, useEffect } from 'react';
import './InspectorPanel.css';
import { X, Type, Palette, Layout, Box, Move3D, Settings, Move, Droplet, ChevronDown, ChevronUp, Trash2 } from 'lucide-react';

interface ElementInfo {
  tagName: string;
  textContent: string;
  className: string;
  id: string;
  styles: {
    color: string;
    backgroundColor: string;
    fontSize: string;
    fontWeight: string;
    margin: string;
    padding: string;
    borderRadius: string;
    width: string;
    height: string;
  };
  innerHTML: string;
}

interface InspectorPanelProps {
  isOpen: boolean;
  selectedElement: ElementInfo | null;
  onClose: () => void;
  onUpdateElement?: (updates: any) => void;
}

const InspectorPanel: React.FC<InspectorPanelProps> = ({
  isOpen,
  selectedElement,
  onClose,
  onUpdateElement
}) => {
  const [activeTab, setActiveTab] = useState('content');
  const [editedContent, setEditedContent] = useState('');
  const [editedStyles, setEditedStyles] = useState<any>({});
  const [openSections, setOpenSections] = useState({ layout: true, typography: false, appearance: false });

  // Update local state when selectedElement changes
  useEffect(() => {
    if (selectedElement) {
      setEditedContent(selectedElement.textContent || '');
      setEditedStyles({
        color: selectedElement.styles.color,
        backgroundColor: selectedElement.styles.backgroundColor,
        fontSize: selectedElement.styles.fontSize,
        fontWeight: selectedElement.styles.fontWeight,
        margin: selectedElement.styles.margin,
        padding: selectedElement.styles.padding,
        borderRadius: selectedElement.styles.borderRadius,
        width: selectedElement.styles.width,
        height: selectedElement.styles.height,
      });
    }
  }, [selectedElement]);

  const handleContentChange = (value: string) => {
    setEditedContent(value);
    onUpdateElement && onUpdateElement({ textContent: value });
  };

  const handleStyleChange = (property: string, value: string) => {
    const newStyles = { ...editedStyles, [property]: value };
    setEditedStyles(newStyles);
    onUpdateElement && onUpdateElement({ styles: { [property]: value } });
  };

  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : null;
  };

  const rgbToHex = (rgb: string) => {
    const match = rgb.match(/\d+/g);
    if (!match) return '#000000';
    return '#' + ((1 << 24) + (parseInt(match[0]) << 16) + (parseInt(match[1]) << 8) + parseInt(match[2])).toString(16).slice(1);
  };

  const toggleSection = (section: string) => {
    setOpenSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  if (!isOpen) return null;

  return (
    <div className="inspector-panel">
      <div className="inspector-header">
        <span className="inspector-title"><Edit3 size={18} /> <b>Edit Component</b></span>
        <button className="close-inspector" onClick={onClose} title="Close"><span aria-hidden>×</span></button>
      </div>
      <div className="inspector-content">
        {/* Accordion: Layout */}
        <div className="accordion-section">
          <button className="accordion-header" onClick={() => toggleSection('layout')}>
            <Move size={16} />
            <span className="accordion-title">Layout</span>
            {openSections.layout ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
          </button>
          {openSections.layout && (
            <div className="accordion-body">
              <div className="property-group">
                <label>Dimensions</label>
                <div className="pill-input-group">
                  <input type="number" className="pill-input" placeholder="Width" />
                  <input type="number" className="pill-input" placeholder="Height" />
                </div>
              </div>
              <div className="property-group">
                <label>Margin</label>
                <div className="pill-input-group">
                  <input type="number" className="pill-input" placeholder="Top" />
                  <input type="number" className="pill-input" placeholder="Right" />
                  <input type="number" className="pill-input" placeholder="Bottom" />
                  <input type="number" className="pill-input" placeholder="Left" />
                </div>
              </div>
              <div className="property-group">
                <label>Padding</label>
                <div className="pill-input-group">
                  <input type="number" className="pill-input" placeholder="Top" />
                  <input type="number" className="pill-input" placeholder="Right" />
                  <input type="number" className="pill-input" placeholder="Bottom" />
                  <input type="number" className="pill-input" placeholder="Left" />
                </div>
              </div>
            </div>
          )}
        </div>
        {/* Accordion: Typography */}
        <div className="accordion-section">
          <button className="accordion-header" onClick={() => toggleSection('typography')}>
            <Type size={16} />
            <span className="accordion-title">Typography</span>
            {openSections.typography ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
          </button>
          {openSections.typography && (
            <div className="accordion-body">
              <div className="property-group">
                <label>Font Size</label>
                <input type="number" className="pill-input" placeholder="Font Size" />
              </div>
              <div className="property-group">
                <label>Font Weight</label>
                <input type="number" className="pill-input" placeholder="Font Weight" />
              </div>
              <div className="property-group">
                <label>Line Height</label>
                <input type="number" className="pill-input" placeholder="Line Height" />
              </div>
            </div>
          )}
        </div>
        {/* Accordion: Appearance */}
        <div className="accordion-section">
          <button className="accordion-header" onClick={() => toggleSection('appearance')}>
            <Droplet size={16} />
            <span className="accordion-title">Appearance</span>
            {openSections.appearance ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
          </button>
          {openSections.appearance && (
            <div className="accordion-body">
              <div className="property-group">
                <label>Background Color</label>
                <input type="color" className="pill-input" />
              </div>
              <div className="property-group">
                <label>Border Radius</label>
                <input type="number" className="pill-input" placeholder="Border Radius" />
              </div>
            </div>
          )}
        </div>
        {/* Delete Button */}
        <button className="delete-element-btn">
          <Trash2 size={18} /> Delete Element
        </button>
      </div>
    </div>
  );
};

export default InspectorPanel;
